const AWS = require('aws-sdk');
const sqs = new AWS.SQS({ region: 'us-east-1' });
const dynamodb = new AWS.DynamoDB.DocumentClient({ region: 'us-east-1' });

exports.handler = async (event) => {
  const orderId = event.Records[0].body;
  const orderDetails = await sqs.receiveMessage({
    QueueUrl: 'https://sqs.us-east-1.amazonaws.com/1234567890/orders',
    MessageAttributeNames: ['All'],
    MaxNumberOfMessages: 1,
    VisibilityTimeout: 30,
  }).promise();

  const order = JSON.parse(orderDetails.Messages[0].Body);
  const paymentMethod = order.paymentMethod;

  let paymentResponse;
  if (paymentMethod === 'credit_card') {
    paymentResponse = await externalPaymentApiCall(orderId, order.amount);
  } else if (paymentMethod === 'paypal') {
    paymentResponse = await paypalApiCall(orderId, order.amount);
  }

  const updateItemParams = {
    TableName: 'Orders',
    Key: { orderId },
    UpdateExpression: 'SET paymentStatus = :status',
    ExpressionAttributeValues: {
      ':status': paymentResponse.paymentStatus,
    },
  };

  try {
    await dynamodb.update(updateItemParams).promise();
  } catch (error) {
    console.log(`Error updating order ${orderId}: ${error}`);
  }
};

const externalPaymentApiCall = async (orderId, amount) => {
  const paymentResponse = await fetch('https://external-payment-api.com/charge', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ orderId, amount }),
  });

  return paymentResponse.json();
};

const paypalApiCall = async (orderId, amount) => {
  const paymentResponse = await fetch('https://paypal.com/api/charge', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ orderId, amount }),
  });

  return paymentResponse.json();
};